const activeCarIds = Object.keys(carRoutes);
const idleCars = (window.cachedCars || []).filter(c => !activeCarIds.includes(String(c.id)));
const idleCarNames = idleCars.map(c => c.model).join(', ');

// Place idle cars at base
const baseIcon = L.divIcon({
  className: 'custom-map-icon',
  html: `<div style="background:#71717a; width:16px; height:16px; border-radius:50%; border:2px solid white; box-shadow:0 2px 5px rgba(0,0,0,0.3);"></div>
         <div style="position:absolute; top:-25px; left:-50%; white-space:nowrap; background:rgba(0,0,0,0.8); color:white; font-size:10px; padding:2px 6px; border-radius:4px; transform:translateX(-25%);">На базі: ${idleCarNames || 'Немає'}</div>`,
  iconSize: [16, 16],
  iconAnchor: [8, 8]
});
L.marker(baseCoords, {icon: baseIcon}).addTo(fleetMap);

// Addresses to geocode
const toGeocode = [];
Object.values(carRoutes).forEach(route => {
  route.deliveries.forEach(d => {
    if (!addressCache[d.address]) {
      toGeocode.push(d.address);
    }
  });
});

// Unique addresses to geocode
const uniqueToGeocode = [...new Set(toGeocode)];

if (uniqueToGeocode.length > 0) {
  for (let i = 0; i < uniqueToGeocode.length; i++) {
    loadingText.textContent = `Завантаження адрес... (${i + 1}/${uniqueToGeocode.length})`;
    await geocodeAddress(uniqueToGeocode[i]);
    if (i < uniqueToGeocode.length - 1) {
      await sleep(1000); // 1 sec delay for Nominatim rate limit
    }
  }
}

loadingOverlay.style.display = 'none';

// Draw markers
const bounds = L.latLngBounds([baseCoords]);

Object.values(carRoutes).forEach(route => {
  route.deliveries.forEach(d => {
    const coords = addressCache[d.address];
    if (coords) {
      bounds.extend([coords.lat, coords.lon]);
      const isCompleted = (d.status === 'Виконано' || d.status === 'Завершено');
      const isProblem = route.incident && !isCompleted;

      let color = '#3b82f6'; // Planned
      if (isCompleted) color = '#10b981'; // Completed
      if (isProblem) color = '#ef4444'; // Incident

      const pulsingCss = isProblem ? 'animation: mapPulse 2s infinite ease-in-out;' : '';
      const pulseKeyframes = isProblem && !document.getElementById('mapPulseAnim') ? `<style id="mapPulseAnim">@keyframes mapPulse { 0% { box-shadow: 0 0 0 0 rgba(239, 68, 68, 0.7); } 70% { box-shadow: 0 0 0 10px rgba(239, 68, 68, 0); } 100% { box-shadow: 0 0 0 0 rgba(239, 68, 68, 0); } }</style>` : '';

      if (pulseKeyframes) document.head.insertAdjacentHTML('beforeend', pulseKeyframes);

      const iconHtml = `
        <div style="background:${color}; width:16px; height:16px; border-radius:50%; border:2px solid white; box-shadow:0 2px 5px rgba(0,0,0,0.3); ${pulsingCss}"></div>
        <div style="position:absolute; top:-25px; left:-50%; white-space:nowrap; background:rgba(0,0,0,0.8); color:white; font-size:10px; padding:2px 6px; border-radius:4px; font-weight:600; transform:translateX(-25%);">${route.model}</div>
      `;

      const customIcon = L.divIcon({
        className: 'custom-map-icon',
        html: iconHtml,
        iconSize: [16, 16],
        iconAnchor: [8, 8]
      });

      L.marker([coords.lat, coords.lon], {icon: customIcon}).addTo(fleetMap).bindPopup(`<b>${route.model}</b><br>${d.address}<br>Час: ${d.time}<br>Статус: ${d.status}`);
    }
  });
});

if (Object.keys(carRoutes).length > 0 || idleCars.length > 0) {
  fleetMap.fitBounds(bounds, {padding: [50, 50], maxZoom: 14});
}

